import { useState, useRef, useEffect } from "react";

const FOOTER_IMG = "data:image/jpeg;base64,";

const SYSTEM_PROMPT = `You are an assistant helping fill out an Accomplishment Activity Report (AAR) for DICT (Department of Information and Communications Technology) Philippines.

Your job is to collect information through a friendly conversation, ONE question at a time. Ask the next question only after getting an answer.

Collect these fields in order:
1. Activity title
2. Date and time (e.g. "December 2-3, 2025 | 9:00am - 5:00pm")
3. Mode/Platform/Location (e.g. "Face-to-Face" or "Online via Zoom")
4. Control number (e.g. "eLGU-R2-12-04-2025-S157")
5. DICT Facilitators - ask for each: Name, Office, Gender (M/F). Ask how many facilitators first, then collect each one.
6. Beneficiary breakdown: how many Male/Female from NGAs, LGUs, SUCs, Others
7. What was the activity about? (for Rationale - you will write the formal rationale based on their answer)
8. Key topics/modules discussed and outcomes (for Highlights - you will write the formal highlights based on their answer)
9. Name and position of the person who prepared the report
10. Name and position of the person who will conform/approve the report

After collecting ALL fields, output ONLY a valid JSON object (no markdown, no explanation) in this exact format:
{
  "title": "",
  "dateTime": "",
  "mode": "",
  "controlNo": "",
  "facilitators": [{"name": "", "office": "", "gender": ""}],
  "beneficiaries": {"ngas": {"male": 0, "female": 0}, "lgus": {"male": 0, "female": 0}, "sucs": {"male": 0, "female": 0}, "others": {"male": 0, "female": 0}},
  "rationale": "",
  "highlights": "",
  "preparedBy": {"name": "", "position": ""},
  "conformedBy": {"name": "", "position": ""}
}

Important:
- Write rationale and highlights in formal, professional government report style (2-3 paragraphs each)
- Only output the JSON when ALL fields are collected
- Keep conversation friendly and clear
- If user says "done" or "that's all" when adding facilitators or asking for more, accept it`;

const INITIAL_MESSAGE = {
  role: "assistant",
  content: "Hello! I'll help you create your Accomplishment Activity Report. Let's start — what is the **title of the activity**?"
};

function ReportPreview({ data, photos }) {
  const facilitatorMale = data.facilitators.filter(f => f.gender?.toUpperCase() === "M").length;
  const facilitatorFemale = data.facilitators.filter(f => f.gender?.toUpperCase() === "F").length;

  const b = data.beneficiaries;
  const benMale = (b.ngas?.male||0)+(b.lgus?.male||0)+(b.sucs?.male||0)+(b.others?.male||0);
  const benFemale = (b.ngas?.female||0)+(b.lgus?.female||0)+(b.sucs?.female||0)+(b.others?.female||0);
  const totalMale = facilitatorMale + benMale;
  const totalFemale = facilitatorFemale + benFemale;

  return (
    <div id="report-preview" style={{fontFamily:"'Times New Roman', serif", fontSize:"11pt", color:"#000", background:"#fff", padding:"40px 48px", maxWidth:"800px", margin:"0 auto"}}>
      {/* Header */}
      <div style={{marginBottom:"16px"}}>
        <img src="data:image/png;base64," style={{width:"100%", maxWidth:"100%", display:"block"}} alt="eLGU eGOVPH Accomplishment Activity Report Header"/>
      </div>

      {/* Info Table */}
      <table style={{width:"100%", borderCollapse:"collapse", marginBottom:"20px", border:"2px solid #0000cc"}}>
        <tbody>
          <tr>
            <td style={{background:"#0000cc", color:"#fff", fontWeight:"bold", padding:"6px 10px", width:"30%"}}>Title</td>
            <td style={{padding:"6px 10px", border:"1px solid #0000cc"}} colSpan="3">{data.title}</td>
          </tr>
          <tr>
            <td style={{background:"#0000cc", color:"#fff", fontWeight:"bold", padding:"6px 10px"}}>Date and Time</td>
            <td style={{padding:"6px 10px", border:"1px solid #0000cc", fontWeight:"bold"}} colSpan="3">{data.dateTime}</td>
          </tr>
          <tr>
            <td style={{background:"#0000cc", color:"#fff", fontWeight:"bold", padding:"6px 10px"}}>Mode/Platform/Location</td>
            <td style={{padding:"6px 10px", border:"1px solid #0000cc"}}>{data.mode}</td>
            <td style={{background:"#0000cc", color:"#fff", fontWeight:"bold", padding:"6px 10px"}}>Control No.</td>
            <td style={{padding:"6px 10px", border:"1px solid #0000cc"}}>{data.controlNo}</td>
          </tr>
          <tr>
            <td style={{background:"#0000cc", color:"#fff", fontWeight:"bold", padding:"6px 10px"}}>Participants</td>
            <td style={{padding:"6px 10px", border:"1px solid #0000cc", color:"#0000cc", textDecoration:"underline"}} colSpan="3">Attached Attendance</td>
          </tr>
        </tbody>
      </table>

      {/* Rationale */}
      <div style={{marginBottom:"20px"}}>
        <div style={{fontWeight:"bold", marginBottom:"8px"}}>I.&nbsp;&nbsp;&nbsp;RATIONALE</div>
        {data.rationale.split("\n").filter(p=>p.trim()).map((p,i) => (
          <p key={i} style={{textAlign:"justify", textIndent:"36px", marginBottom:"8px", lineHeight:"1.8"}}>{p}</p>
        ))}
      </div>

      {/* Attendees */}
      <div style={{marginBottom:"20px"}}>
        <div style={{fontWeight:"bold", marginBottom:"8px"}}>II.&nbsp;&nbsp;ATTENDEES</div>
        <div style={{fontWeight:"bold", fontStyle:"italic", marginBottom:"6px", paddingLeft:"24px"}}>A. Facilitator (DICT)</div>
        <table style={{width:"100%", borderCollapse:"collapse", marginBottom:"8px"}}>
          <thead>
            <tr>
              {["Name","Office","Gender"].map(h => (
                <th key={h} style={{background:"#0000cc", color:"#fff", padding:"6px 10px", border:"1px solid #0000cc"}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {data.facilitators.map((f,i) => (
              <tr key={i}>
                <td style={{padding:"5px 10px", border:"1px solid #ccc"}}>{f.name}</td>
                <td style={{padding:"5px 10px", border:"1px solid #ccc"}}>{f.office}</td>
                <td style={{padding:"5px 10px", border:"1px solid #ccc", textAlign:"center"}}>{f.gender}</td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{textAlign:"right", fontWeight:"bold", marginBottom:"16px"}}>Male: {facilitatorMale} | Female: {facilitatorFemale}</div>

        <div style={{fontWeight:"bold", fontStyle:"italic", marginBottom:"6px", paddingLeft:"24px"}}>B. NGAs / LGUs / SUCs and other Beneficiaries <span style={{fontStyle:"italic", fontWeight:"normal"}}>(please see attached attendance sheet)</span></div>
        <table style={{width:"100%", borderCollapse:"collapse", marginBottom:"8px"}}>
          <thead>
            <tr>
              <th colSpan="2" style={{background:"#0000cc", color:"#fff", padding:"6px", border:"1px solid #0000cc"}}>NGAs</th>
              <th colSpan="2" style={{background:"#0000cc", color:"#fff", padding:"6px", border:"1px solid #0000cc"}}>LGUs</th>
              <th colSpan="2" style={{background:"#0000cc", color:"#fff", padding:"6px", border:"1px solid #0000cc"}}>SUCs</th>
              <th colSpan="2" style={{background:"#0000cc", color:"#fff", padding:"6px", border:"1px solid #0000cc"}}>Others</th>
            </tr>
            <tr>
              {["Male","Female","Male","Female","Male","Female","Male","Female"].map((g,i) => (
                <th key={i} style={{background:"#eef", padding:"5px 6px", border:"1px solid #ccc", fontWeight:"normal"}}>{g}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            <tr>
              {[b.ngas?.male,b.ngas?.female,b.lgus?.male,b.lgus?.female,b.sucs?.male,b.sucs?.female,b.others?.male,b.others?.female].map((v,i) => (
                <td key={i} style={{padding:"5px 6px", border:"1px solid #ccc", textAlign:"center"}}>{v||""}</td>
              ))}
            </tr>
          </tbody>
        </table>
        <div style={{textAlign:"right", fontWeight:"bold", marginBottom:"16px"}}>Male: {benMale} | Female: {benFemale}</div>

        <div style={{fontWeight:"bold", fontStyle:"italic", marginBottom:"6px", paddingLeft:"24px"}}>C. Consolidated participants</div>
        <table style={{width:"60%", borderCollapse:"collapse"}}>
          <tbody>
            <tr><td style={{padding:"5px 10px", border:"1px solid #ccc"}}>Total number of male attendees</td><td style={{padding:"5px 20px", border:"1px solid #ccc", textAlign:"center"}}>{totalMale}</td></tr>
            <tr><td style={{padding:"5px 10px", border:"1px solid #ccc"}}>Total number of female attendees</td><td style={{padding:"5px 20px", border:"1px solid #ccc", textAlign:"center"}}>{totalFemale}</td></tr>
            <tr><td style={{padding:"6px 10px", border:"1px solid #0000cc", background:"#0000cc", color:"#fff", fontWeight:"bold"}}>Total number of attendees</td><td style={{padding:"6px 20px", border:"1px solid #0000cc", background:"#0000cc", color:"#fff", fontWeight:"bold", textAlign:"center"}}>{totalMale+totalFemale}</td></tr>
          </tbody>
        </table>
      </div>

      {/* Highlights */}
      <div style={{marginBottom:"20px"}}>
        <div style={{fontWeight:"bold", marginBottom:"8px"}}>III.&nbsp;HIGHLIGHTS OF DISCUSSION</div>
        {data.highlights.split("\n").filter(p=>p.trim()).map((p,i) => (
          <p key={i} style={{textAlign:"justify", textIndent:"36px", marginBottom:"8px", lineHeight:"1.8", paddingLeft:"24px"}}>{p}</p>
        ))}
        <div style={{textAlign:"center", fontStyle:"italic", marginTop:"12px", fontSize:"9pt"}}>
          [{data.title} on {data.dateTime?.split("|")[0]?.trim()}]
        </div>
      </div>

      {/* Annexes */}
      <div style={{marginBottom:"20px"}}>
        <div style={{fontWeight:"bold", marginBottom:"8px"}}>IV.&nbsp;&nbsp;ANNEXES</div>
        <div style={{fontWeight:"bold", fontStyle:"italic", marginBottom:"12px", paddingLeft:"24px"}}>A. PHOTOS <span style={{fontStyle:"italic", fontWeight:"normal"}}>(must be action picture)</span></div>
        {photos.length > 0 ? (
          <div style={{display:"grid", gridTemplateColumns:"1fr 1fr", gap:"4px", border:"2px solid #0000cc", padding:"4px"}}>
            {photos.slice(0,4).map((p,i) => (
              <img key={i} src={p} alt={`Photo ${i+1}`} style={{width:"100%", aspectRatio:"4/3", objectFit:"cover"}}/>
            ))}
          </div>
        ) : (
          <div style={{border:"2px dashed #aaa", padding:"40px", textAlign:"center", color:"#999", margin:"0 0 16px 24px"}}>Upload photos using the button above</div>
        )}
        {photos.length > 4 && (
          <div style={{display:"grid", gridTemplateColumns:"1fr 1fr", gap:"4px", border:"2px solid #0000cc", padding:"4px", marginTop:"4px"}}>
            {photos.slice(4,8).map((p,i) => (
              <img key={i} src={p} alt={`Photo ${i+5}`} style={{width:"100%", aspectRatio:"4/3", objectFit:"cover"}}/>
            ))}
          </div>
        )}
      </div>

      {/* Signatures */}
      <table style={{width:"100%", borderCollapse:"collapse", border:"1px solid #ccc"}}>
        <tbody>
          <tr>
            <td style={{padding:"12px 16px", border:"1px solid #ccc", width:"50%", verticalAlign:"top"}}>
              <div style={{fontWeight:"bold", marginBottom:"40px"}}>Prepared by:</div>
              <div style={{fontWeight:"bold"}}>{data.preparedBy?.name}</div>
              <div>{data.preparedBy?.position}</div>
            </td>
            <td style={{padding:"12px 16px", border:"1px solid #ccc", verticalAlign:"top"}}>
              <div style={{fontWeight:"bold", marginBottom:"40px"}}>Conformed by:</div>
              <div style={{fontWeight:"bold"}}>{data.conformedBy?.name}</div>
              <div>{data.conformedBy?.position}</div>
            </td>
          </tr>
        </tbody>
      </table>
      <div style={{marginTop:"8px", fontStyle:"italic", color:"#0000cc", fontSize:"10pt"}}>Copy furnish: eLGU Project Management Team</div>

      {/* Footer */}
      <div style={{marginTop:"20px", overflow:"hidden"}}>
        <div style={{display:"flex", justifyContent:"space-between", alignItems:"center", fontSize:"9pt", marginBottom:"6px"}}>
          <div style={{fontStyle:"italic"}}>[{data.title} on {data.dateTime?.split("|")[0]?.trim()}]</div>
          <div style={{fontWeight:"bold", color:"#0000cc"}}>PAGE 3 OF 3</div>
        </div>
        <img src={FOOTER_IMG} alt="footer" style={{width:"100%", display:"block", marginTop:"4px"}}/>
      </div>
    </div>
  );
}

export default function AARApp() {
  const [messages, setMessages] = useState([INITIAL_MESSAGE]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [reportData, setReportData] = useState(null);
  const [photos, setPhotos] = useState([]);
  const [tab, setTab] = useState("chat"); // chat | preview
  const chatRef = useRef(null);
  const fileRef = useRef(null);

  useEffect(() => {
    if (chatRef.current) chatRef.current.scrollTop = chatRef.current.scrollHeight;
  }, [messages]);

  const sendMessage = async () => {
    if (!input.trim() || loading) return;
    const userMsg = { role: "user", content: input.trim() };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setLoading(true);

    try {
      const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
        method: "POST",
        headers: { 
          "Content-Type": "application/json",
          "Authorization": `Bearer ${CONFIG.OPENROUTER_API_KEY}`,
          "HTTP-Referer": "https://yoursite.com",
          "X-Title": "AAR Generator"
        },
        body: JSON.stringify({
          model: "anthropic/claude-3.5-sonnet",
          max_tokens: 1000,
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            ...newMessages.map(m => ({ role: m.role, content: m.content }))
          ]
        })
      });
      const data = await res.json();
      const text = data.choices?.[0]?.message?.content || "";

      // Try to detect JSON output
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        try {
          const parsed = JSON.parse(jsonMatch[0]);
          setReportData(parsed);
          setMessages(prev => [...prev, {
            role: "assistant",
            content: "✅ **Report data collected!** Click the **Preview Report** tab to see your formatted AAR. Don't forget to upload photos!"
          }]);
          setTab("preview");
        } catch {
          setMessages(prev => [...prev, { role: "assistant", content: text }]);
        }
      } else {
        setMessages(prev => [...prev, { role: "assistant", content: text }]);
      }
    } catch (e) {
      setMessages(prev => [...prev, { role: "assistant", content: "Sorry, there was an error. Please try again." }]);
    }
    setLoading(false);
  };

  const handlePhotos = (e) => {
    const files = Array.from(e.target.files);
    files.forEach(f => {
      const reader = new FileReader();
      reader.onload = (ev) => setPhotos(prev => [...prev, ev.target.result]);
      reader.readAsDataURL(f);
    });
  };

  const handlePrint = () => {
    const content = document.getElementById("report-preview");
    const w = window.open("", "_blank");
    w.document.write(`<html><head><title>AAR</title><style>body{margin:0;padding:0;}</style></head><body>${content.innerHTML}</body></html>`);
    w.document.close();
    w.focus();
    w.print();
    w.close();
  };

  const renderMessage = (msg, i) => {
    const isUser = msg.role === "user";
    return (
      <div key={i} style={{
        display:"flex", justifyContent: isUser ? "flex-end" : "flex-start",
        marginBottom:"12px"
      }}>
        {!isUser && (
          <div style={{width:"32px", height:"32px", borderRadius:"50%", background:"linear-gradient(135deg,#0033cc,#0099ff)", display:"flex", alignItems:"center", justifyContent:"center", color:"#fff", fontSize:"11px", fontWeight:"bold", flexShrink:0, marginRight:"8px", marginTop:"4px"}}>AI</div>
        )}
        <div style={{
          maxWidth:"72%", padding:"10px 14px", borderRadius: isUser ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
          background: isUser ? "linear-gradient(135deg,#0033cc,#0055ff)" : "#f0f4ff",
          color: isUser ? "#fff" : "#1a1a2e",
          fontSize:"14px", lineHeight:"1.6", boxShadow:"0 2px 8px rgba(0,0,50,0.1)"
        }}
          dangerouslySetInnerHTML={{__html: msg.content.replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>").replace(/\n/g,"<br/>")}}
        />
      </div>
    );
  };

  return (
    <div style={{
      fontFamily:"'Segoe UI', system-ui, sans-serif",
      minHeight:"100vh",
      background:"linear-gradient(135deg, #f0f4ff 0%, #e8f0fe 50%, #f5f0ff 100%)",
      display:"flex", flexDirection:"column"
    }}>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#0011aa,#0033cc)", padding:"14px 24px", display:"flex", alignItems:"center", gap:"16px", boxShadow:"0 2px 16px rgba(0,0,150,0.3)"}}>
        <div>
          <div style={{color:"#fff", fontSize:"18px", fontWeight:"900", letterSpacing:"-0.5px"}}>
            <span style={{color:"#66aaff"}}>e</span>LGU <span style={{color:"#ffaa33"}}>e</span><span style={{color:"#66ff88"}}>GOV</span><span style={{color:"#ff6666", fontSize:"12px"}}>PH</span>
            <span style={{color:"rgba(255,255,255,0.6)", fontSize:"13px", fontWeight:"400", marginLeft:"10px"}}>AAR Generator</span>
          </div>
          <div style={{color:"rgba(255,255,255,0.6)", fontSize:"11px", marginTop:"1px"}}>AI-Powered Accomplishment Activity Report</div>
        </div>
        <div style={{marginLeft:"auto", display:"flex", gap:"8px"}}>
          {["chat","preview"].map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              padding:"7px 16px", borderRadius:"20px", border:"none", cursor:"pointer", fontSize:"12px", fontWeight:"600",
              background: tab===t ? "#fff" : "rgba(255,255,255,0.15)",
              color: tab===t ? "#0033cc" : "#fff", transition:"all .2s"
            }}>
              {t === "chat" ? "💬 Chat" : "📄 Preview Report"}
            </button>
          ))}
          {reportData && tab==="preview" && (
            <>
              <button onClick={() => fileRef.current?.click()} style={{padding:"7px 16px", borderRadius:"20px", border:"none", cursor:"pointer", fontSize:"12px", fontWeight:"600", background:"rgba(255,255,255,0.15)", color:"#fff"}}>
                📷 Upload Photos
              </button>
              <button onClick={handlePrint} style={{padding:"7px 16px", borderRadius:"20px", border:"none", cursor:"pointer", fontSize:"12px", fontWeight:"600", background:"#ff6600", color:"#fff"}}>
                🖨️ Print / Save PDF
              </button>
            </>
          )}
        </div>
      </div>
      <input ref={fileRef} type="file" multiple accept="image/*" style={{display:"none"}} onChange={handlePhotos}/>

      {/* Body */}
      <div style={{flex:1, overflow:"auto", padding:"24px", display:"flex", justifyContent:"center"}}>
        {tab === "chat" ? (
          <div style={{width:"100%", maxWidth:"680px", display:"flex", flexDirection:"column", height:"calc(100vh - 140px)"}}>
            {/* Progress hint */}
            <div style={{background:"rgba(0,51,204,0.08)", borderRadius:"12px", padding:"10px 16px", marginBottom:"16px", fontSize:"12px", color:"#0033cc", border:"1px solid rgba(0,51,204,0.15)"}}>
              💡 Answer each question to build your AAR. The AI will collect all required info and generate your formal report automatically.
            </div>
            {/* Messages */}
            <div ref={chatRef} style={{flex:1, overflowY:"auto", paddingRight:"4px"}}>
              {messages.map(renderMessage)}
              {loading && (
                <div style={{display:"flex", marginBottom:"12px"}}>
                  <div style={{width:"32px", height:"32px", borderRadius:"50%", background:"linear-gradient(135deg,#0033cc,#0099ff)", display:"flex", alignItems:"center", justifyContent:"center", color:"#fff", fontSize:"11px", fontWeight:"bold", flexShrink:0, marginRight:"8px"}}>AI</div>
                  <div style={{background:"#f0f4ff", padding:"12px 16px", borderRadius:"18px 18px 18px 4px", display:"flex", gap:"4px", alignItems:"center"}}>
                    {[0,1,2].map(i => <div key={i} style={{width:"7px", height:"7px", borderRadius:"50%", background:"#0033cc", animation:"bounce 1s infinite", animationDelay:`${i*0.15}s`}}/>)}
                  </div>
                </div>
              )}
            </div>
            {/* Input */}
            <div style={{display:"flex", gap:"10px", marginTop:"16px"}}>
              <input
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key==="Enter" && !e.shiftKey && sendMessage()}
                placeholder="Type your answer..."
                style={{flex:1, padding:"12px 18px", borderRadius:"24px", border:"2px solid #c0ccff", outline:"none", fontSize:"14px", background:"#fff", transition:"border .2s"}}
                onFocus={e => e.target.style.border="2px solid #0033cc"}
                onBlur={e => e.target.style.border="2px solid #c0ccff"}
              />
              <button onClick={sendMessage} disabled={loading} style={{
                padding:"12px 24px", borderRadius:"24px", border:"none", cursor:"pointer",
                background: loading ? "#aaa" : "linear-gradient(135deg,#0033cc,#0055ff)",
                color:"#fff", fontWeight:"700", fontSize:"14px", transition:"all .2s"
              }}>Send</button>
            </div>
          </div>
        ) : (
          <div style={{width:"100%", maxWidth:"850px"}}>
            {reportData ? (
              <div style={{background:"#fff", borderRadius:"12px", overflow:"hidden", boxShadow:"0 4px 24px rgba(0,0,100,0.15)"}}>
                <ReportPreview data={reportData} photos={photos}/>
              </div>
            ) : (
              <div style={{textAlign:"center", padding:"80px 24px", color:"#666"}}>
                <div style={{fontSize:"48px", marginBottom:"16px"}}>📋</div>
                <div style={{fontSize:"20px", fontWeight:"600", color:"#333", marginBottom:"8px"}}>No report yet</div>
                <div>Complete the chat conversation to generate your report.</div>
                <button onClick={() => setTab("chat")} style={{marginTop:"20px", padding:"10px 24px", borderRadius:"20px", border:"none", background:"#0033cc", color:"#fff", fontWeight:"600", cursor:"pointer"}}>Go to Chat →</button>
              </div>
            )}
          </div>
        )}
      </div>

      <style>{`
        @keyframes bounce { 0%,80%,100%{transform:translateY(0)} 40%{transform:translateY(-6px)} }
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #c0ccff; border-radius: 3px; }
      `}</style>
    </div>
  );
}
